98						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
99					})
100				});
101			} else if (body.query.includes('DocGraph')) {
102				await route.fulfill({
103					status: 200,
104					contentType: 'application/json',
105					body: JSON.stringify({ data: makeGraphResponse(docs, warnings, issues) })
106				});
107			} else if (body.query.includes('DocStale')) {
