119	function ensureDdxBinary(): string {
120		if (ddxBinary) return ddxBinary;
121	
122		const binDir = fs.mkdtempSync(path.join(os.tmpdir(), 'ddx-graph-e2e-bin-'));
123		ddxBinary = path.join(binDir, process.platform === 'win32' ? 'ddx-e2e.exe' : 'ddx-e2e');
124		const result = spawnSync('go', ['build', '-o', ddxBinary, '.'], {
125			cwd: CLI_DIR,
126			env: process.env,
127			encoding: 'utf8'
128		});
129		if (result.status !== 0) {
130			throw new Error(`failed to build ddx test binary\n${result.stdout}\n${result.stderr}`);
131		}
132		return ddxBinary;
133	}
