188	async function startRealDdxServer(fixtureRoot: string): Promise<RealServer> {
189		const port = await freePort();
190		const bin = ensureDdxBinary();
191		const child = spawn(bin, ['server', '--port', String(port), '--tsnet=false'], {
192			cwd: fixtureRoot,
193			env: {
194				...process.env,
195				DDX_NODE_NAME: 'graph-e2e-node',
196				XDG_DATA_HOME: path.join(fixtureRoot, '.xdg-data')
197			}
198		});
199		child.stdout.resume();
200		child.stderr.resume();
201		const baseURL = `https://127.0.0.1:${port}`;
202		const api = await playwrightRequest.newContext({ baseURL, ignoreHTTPSErrors: true });
203	
204		let lastError: unknown;
205		for (let i = 0; i < 80; i++) {
206			if (child.exitCode !== null) {
207				throw new Error(`ddx server exited early with code ${child.exitCode}`);
208			}
209			try {
210				const resp = await api.get('/api/health', { timeout: 500 });
211				if (resp.ok()) {
212					const infoResp = await api.post('/graphql', {
213						data: {
214							query: `query E2EProjectInfo {
215								nodeInfo { id name }
216								projects { edges { node { id name path } } }
217							}`
218						}
219					});
220					const payload = (await infoResp.json()) as {
221						data: {
222							nodeInfo: { id: string };
223							projects: { edges: Array<{ node: { id: string } }> };
224						};
225					};
226					const projectId = payload.data.projects.edges[0]?.node.id;
227					if (!projectId) throw new Error('ddx server returned no registered project');
228					return {
229						api,
230						nodeId: payload.data.nodeInfo.id,
231						projectId,
232						process: child,
233						root: fixtureRoot
234					};
235				}
236			} catch (err) {
237				lastError = err;
238			}
239			await new Promise((resolve) => setTimeout(resolve, 125));
240		}
241	
242		child.kill();
243		await api.dispose();
244		throw new Error(`ddx server did not become healthy: ${String(lastError)}`);
245	}
